function inferTags(name:string,pos:Pos,attrs:number[]){const tags:string[]=[];if(attrs[0]>=90)tags.push("PACE ABUSER");if(attrs[1]>=90)tags.push(pos==="ATT"?"POACHER":"GOAL THREAT");if(attrs[2]>=90)tags.push("CREATIVE PASSER");if(attrs[3]>=94)tags.push("PRESS RESISTANT");if(attrs[4]>=90)tags.push(pos==="GK"?"SHOT STOPPER":"DEFENSIVE WALL");if(attrs[5]>=92)tags.push("PHYSICAL FORCE");if(TIMELESS.has(name))tags.unshift("ERA PROOF");return [...(SPECIAL_TAGS[name]||[]),...tags].filter((tag,index,all)=>all.indexOf(tag)===index)}
const TAG_ATTRIBUTES:Record<string,number[]>={"PACE ABUSER":[0],"CHANNEL RUNNER":[0],"OVERLAPPING FULLBACK":[0],"POACHER":[1],"GOAL THREAT":[1],"BOX MASTER":[1],"CLUTCH FINISHER":[1],"LONG SHOT SPECIALIST":[1],"CREATIVE PASSER":[2],"SET PIECE MASTER":[2],"SWEEPER KEEPER":[2],"WIDE CREATOR":[2],"TEMPO CONTROLLER":[2],"FALSE NINE":[2],"MAESTRO":[2],"CROSSING SPECIALIST":[2],"DEEP-LYING PLAYMAKER":[2],"PRESS RESISTANT":[3],"CUT INSIDE":[3],"SHOWMAN":[3],"ONE-ON-ONE KING":[3],"SHOT STOPPER":[4],"DEFENSIVE WALL":[4],"LIBERO":[4],"BALL WINNER":[4],"COMMANDING KEEPER":[4],"PHYSICAL FORCE":[5],"AERIAL DOMINANCE":[5],"MIDFIELD ENGINE":[5],"TARGET FORWARD":[5],"PRESSING FORWARD":[5],"TOTAL FOOTBALLER":[0,2,3,4,5]};
function tagTier(p:Player,tag:string){if(UTILITY_TAGS.has(tag)||tag==="TOTAL FOOTBALLER")return 1;const index=(TAG_ATTRIBUTES[tag]||[5])[0],value=p.attrs[index];return value>=97?1:value>=92?2:3}
function tagPoints(p:Player,tag:string){if(UTILITY_TAGS.has(tag))return 0;return tagTier(p,tag)===1?3:tagTier(p,tag)===2?2:1}
function tagEffect(p:Player,tag:string){if(tag==="ERA PROOF")return "100% ERA FIT";if(tag==="MULTI POSITION")return "UTILITY PROFILE · REWORK PENDING";return `T${tagTier(p,tag)} / STAT +${tagPoints(p,tag)}`}
