function playerDecade(p:Player){
  if(p.name==="Franz Beckenbauer") return 70;
  const year=Number(p.era.match(/\d{4}/)?.[0]||2000);
  return Math.floor(year/10)*10%100;
}
function eraFit(p:Player,eraId:string){
  if(p.timeless)return 100;
  const eraStarts:Record<string,number>={"80s":1980,"90s":1990,"00s":2000,"10s":2010,"20s":2020};
  const targetStart=eraStarts[eraId]??2000,targetEnd=targetStart+9;
  const [careerStart,careerEnd]=p.activeYears;
  const gap=careerEnd<targetStart?targetStart-careerEnd:careerStart>targetEnd?careerStart-targetEnd:0;
  const base=gap===0?100:gap<=5?94:gap<=10?89:gap<=20?82:75;
  const styleBonus=eraId==="80s"?p.attrs[5]>90?2:0:eraId==="90s"?p.attrs[3]>90?2:0:eraId==="00s"?p.attrs[2]>90?2:0:eraId==="10s"?p.attrs[0]>90?2:0:p.attrs[2]>90?2:0;
  return Math.min(100,base+styleBonus);
}
function slotCode(slot:string):Role|"FLEX"|"DEF"|"MID"|"ATT"{const clean=slot.replace(/\d+$/,"") as Role;if(["FLEX","DEF","MID","ATT"].includes(clean))return clean as "FLEX"|"DEF"|"MID"|"ATT";return clean}
function slotLabel(slot:string){return slot.replace(/\d+$/,"")}
function positionFit(p:Player,slot:string){const target=slotCode(slot);if(target==="FLEX"||target==="DEF"||target==="MID"||target==="ATT")return 100;if(target==="GK")return p.pos==="GK"?100:50;if(p.pos==="GK")return 45;if(naturalRoles(p.pos).includes(target))return 100;if(p.pos==="ATT")return ["LM","CM","RM"].includes(target)?72:55;if(p.pos==="MID")return ["LW","ST","RW","CF","LF","RF"].includes(target)?82:76;return ["LM","CM","RM","AM"].includes(target)?70:55}
