function playerPartnerships(p:Player){return PARTNERSHIPS.filter(link=>link.players.some(name=>name===p.name))}
function clubChemistry(picks:Pick[]){const counts=new Map<string,number>();picks.forEach(p=>counts.set(p.club,(counts.get(p.club)||0)+1));const playerBonus:Record<string,number>={},activated:string[]=[];let teamBonus=0;for(const [club,count] of counts){const value=count>=7?3:count>=6?2:count>=4?1:0;if(!value)continue;const level=value===3?"GOLD":value===2?"SILVER":"BRONZE";picks.filter(p=>p.club===club).forEach(p=>playerBonus[p.id]=value);teamBonus+=value;activated.push(`${club.toUpperCase()} ${level} CORE · +${value} OVR`)}return {playerBonus,teamBonus:Math.min(6,teamBonus),activated}}
function squadTagBonus(picks:Pick[],coach?:Coach){const tagged=(name:string)=>picks.filter(p=>p.tags.includes(name)),names=new Set(picks.map(p=>p.name)),clubLinks=clubChemistry(picks);let bonus=clubLinks.teamBonus,attack=0,control=clubLinks.teamBonus,defence=0;const activated=[...clubLinks.activated];for(const link of PARTNERSHIPS){if(link.players.every(name=>names.has(name))){bonus+=link.bonus;attack+=link.attack;control+=link.control;defence+=link.defence;activated.push(`${link.name} · ${link.players.length===2?"DUO":"TRIO"} · ${link.effect.toUpperCase()}`)}}const creators=tagged("CREATIVE PASSER");if(coach?.attack==="S"&&creators.length>=2){const value=Math.min(3,Math.round(creators.reduce((s,p)=>s+tagPoints(p,"CREATIVE PASSER"),0)/2));bonus+=value;attack+=value;control+=value;activated.push(`CREATOR'S SYSTEM · +${value} CHEM/ATT/CTRL`)}const press=picks.filter(p=>p.tags.includes("PRESS RESISTANT")||p.tags.includes("PHYSICAL FORCE"));if(coach?.pressing==="S"&&press.length>=3){bonus+=3;control+=3;defence+=1;activated.push("PRESS-PROOF XI · +3 CHEM/CTRL · +1 DEF")}const walls=picks.filter(p=>p.tags.includes("DEFENSIVE WALL")||p.tags.includes("SHOT STOPPER"));if(coach?.defence==="S"&&walls.length>=2){bonus+=3;defence+=4;activated.push("FORTRESS UNIT · +3 CHEM · +4 DEF")}return {bonus:Math.min(12,bonus),attack:Math.min(10,attack),control:Math.min(10,control),defence:Math.min(10,defence),activated}}
