    const lineAverage=(roles:string[],dimension:"attack"|"control"|"defence",fallback=avg)=>{const line=rated.filter(p=>roles.includes(p.role));return line.length?line.reduce((sum,p)=>sum+p.rating+tagLineBoost(p.player,dimension),0)/line.length:fallback};
