function TagGuide(){return <details className="tag-guide"><summary><span>TAG HANDBOOK</span><b>Every boost, partnership and activation rule</b><i>+</i></summary><div className="handbook-content"><aside><b>HOW INDIVIDUAL TAGS WORK</b><p>Tags never add directly to OVR. They improve only their named attribute: T1 +3, T2 +2 or T3 +1. Different attributes may each receive a boost, but duplicate tags on the same attribute use only the strongest value. Partnerships and tactical links are calculated separately.</p></aside><h3>PLAYSTYLE TAGS</h3><div className="handbook-grid">{TAG_GUIDE.map(([tag,boost,copy])=><article key={tag}><strong>{tag}</strong><b>{boost}</b><p>{copy}</p></article>)}</div><h3>PARTNERSHIPS</h3><div className="handbook-grid partnerships-guide">{PARTNERSHIPS.map(link=><article key={link.name}><strong>{link.name}</strong><b>{link.players.length===2?"DYNAMIC DUO":"DYNAMIC TRIO"}</b><p>{link.players.join(" + ")}</p><small>{link.effect}</small></article>)}</div><h3>TACTICAL SYSTEMS</h3><div className="handbook-grid">{SYSTEM_GUIDE.map(([tag,boost,copy])=><article key={tag}><strong>{tag}</strong><b>{boost}</b><p>{copy}</p></article>)}</div></div></details>}
